@code {
    private EditContext editContext = default!;
    private CustomValidator? customValidator;
    private AppointmentFormModel Model { get; set; } = new();

    private bool showStep2;
    private bool isSubmitting;
    private bool appointmentConfirmed;

    private List<string> doctors = new();
    private List<string> availableSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step 1 fields
        var isValid = true;
        var messageStore = new ValidationMessageStore(editContext);
        messageStore.Clear();

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            messageStore.Add(editContext.Field(nameof(Model.PatientName)), "Patient Name is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            messageStore.Add(editContext.Field(nameof(Model.Email)), "Email is required.");
            isValid = false;
        }
        else if (!new EmailAddressAttribute().IsValid(Model.Email))
        {
            messageStore.Add(editContext.Field(nameof(Model.Email)), "Please enter a valid email address.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            messageStore.Add(editContext.Field(nameof(Model.Phone)), "Phone is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            messageStore.Add(editContext.Field(nameof(Model.InsuranceProvider)), "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();

        // Validate step 2 fields with data annotations
        if (!editContext.Validate())
            return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email!,
                Model.InsuranceProvider,
                Model.Doctor,
                Model.TimeSlot);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            appointmentConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public class AppointmentFormModel
    {
        [Required(ErrorMessage = "Patient Name is required.")]
        public string? PatientName { get; set; }

        [Required(ErrorMessage = "Email is required.")]
        [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
        public string? Email { get; set; }

        [Required(ErrorMessage = "Phone is required.")]
        public string? Phone { get; set; }

        [Required(ErrorMessage = "Insurance Provider is required.")]
        public string InsuranceProvider { get; set; } = "";

        [Required(ErrorMessage = "Preferred Doctor is required.")]
        public string Doctor { get; set; } = "";

        [Required(ErrorMessage = "Appointment Date is required.")]
        [FutureDate(ErrorMessage = "Date must be in the future.")]
        public DateOnly? AppointmentDate { get; set; }

        [Required(ErrorMessage = "Time Slot is required.")]
        public string TimeSlot { get; set; } = "";

        [Required(ErrorMessage = "Reason for visit is required.")]
        [MaxLength(500, ErrorMessage = "Reason must be 500 characters or less.")]
        public string? ReasonForVisit { get; set; }
    }

    public class FutureDateAttribute : ValidationAttribute
    {
        protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
        {
            if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
            {
                return new ValidationResult(ErrorMessage);
            }
            return ValidationResult.Success;
        }
    }
}
